import {
  ArrowLeft, Users, Star, Calendar, MessageSquare,
  GraduationCap, Mail, FileText, Send, CheckCircle, Clock,
} from 'lucide-react'

interface JobInfo {
  id: number
  title: string
}

interface Applicant {
  id: number
